                display: 'flex', alignItems: 'center', gap: '0.5rem',
                fontSize: '0.82rem', color: 'var(--text-secondary)',
              }}>
                <span style={{ fontSize: '1.1rem' }}>{emoji}</span>
                <span style={{ fontWeight: 500, color: 'var(--text-primary)' }}>{label.trim()}</span>
