          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <tabConfig.Icon size={18} style={{ color: tabConfig.color }} />
              <h3 style={{ margin: 0 }}>{typeLabel} Categories</h3>
              <span className="badge badge-blue" style={{ fontSize: '0.65rem' }}>
                {filtered.length}
