                <LockOpen size={16} /> Remove Password Protection
              </button>
            </div>
          </div>
        )}

        {/* Set password */}
        {(mode === 'set') && !success && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            <div className="alert alert-info">
              <AlertCircle size={16} />
